    // BBPD decision on data transition.
    @(cross(V(data) - vth, +1) or cross(V(data) - vth, -1)) begin
        if ((V(clk) > vth) && (V(retimed_data) <= vth)) begin
            up_state = 1;
            down_state = 0;
        end else if ((V(clk) <= vth) && (V(retimed_data) > vth)) begin
            up_state = 0;
            down_state = 1;
        end else begin
            up_state = 0;
            down_state = 0;
        end
        $strobe("[bbpd] t=%.3f ns | clk=%.3fV | retimed=%.3fV | up=%d down=%d",
            $abstime * 1e9, V(clk), V(retimed_data), up_state, down_state);
    end

    // Clear pulse on the next clock edge.
    @(cross(V(clk) - vth, +1) or cross(V(clk) - vth, -1)) begin
        up_state = 0;
        down_state = 0;
    end

    V(up)   <+ transition(up_state ? vdd : 0.0, td, trf, trf);
    V(down) <+ transition(down_state ? vdd : 0.0, td, trf, trf);
end

endmodule

