            //   counter=0 → gate=1 (pulse 1 high phase)
            //   counter=1 → gate=1 (pulse 2 high phase)
            //   counter>=2 → gate=0
            gate_q    = (counter_q < 2) ? 1 : 0;
            counter_q = counter_q + 1;
            if (counter_q >= div) counter_q = 0;
        end
        $strobe("[clk_burst_gen] t=%.3f ns | counter=%d | gate=%d", $abstime*1e9, counter_q, gate_q);
    end

    @(cross(V(CLK) - vth, -1))
        clk_hi = 0;

    V(CLK_OUT) <+ transition((gate_q && clk_hi) ? vdd : 0.0);
end

endmodule

