            clk_level  = (cnt < (div_ratio / 2)) ? vdd : 0.0;
            lock_level = locked ? vdd : 0.0;
        end
    end

    V(CLK_OUT) <+ transition(clk_level,  0, tedge, tedge);
    V(LOCK)    <+ transition(lock_level, 0, tedge, tedge);
end

endmodule

