// 3-bit Flash ADC (behavioral) — EVAS-compatible
// 7 comparator levels uniformly spaced between vrefn and vrefp.
// Thermometer code -> binary encoding. Output latched on rising CLK edge.
// Bit outputs stored as piecewise-constant reals (updated in @(cross) block).

`include "constants.vams"
`include "disciplines.vams"

`default_transition 10p

module flash_adc_3b(
    inout  electrical VDD,
    inout  electrical VSS,
    input  electrical VIN,
    input  electrical CLK,
    output electrical DOUT2,
    output electrical DOUT1,
    output electrical DOUT0
);

parameter real vrefp  = 0.9;
parameter real vrefn  = 0.0;
parameter real vth    = 0.45;
parameter real tedge  = 100p;

real lsb;
integer code;
// piecewise-constant output bits
real b2, b1, b0;

analog begin
