module noise_gen (
    input electrical  vin_i,
    output electrical vout_o
);

    // -------------------------------------------------------
    // Parameters
    // -------------------------------------------------------
    parameter real sigma = 0.01;  // Noise standard deviation (in Volts)

    // -------------------------------------------------------
    // Internal variables
    // -------------------------------------------------------
    real vin, noise, vout;

    // -------------------------------------------------------
    // Analog behavior
    // -------------------------------------------------------
    analog begin
        @(initial_step)
            $strobe("[noise_gen] INIT | sigma=%.5gV", sigma);

        // Read input voltage
        vin = V(vin_i);

        // Generate Gaussian noise (zero-mean, bidirectional)
        noise = sigma * $rdist_normal(0, 0, 1);

        // Output = Input + Noise
        vout = vin + noise;

        // Write output voltage
        V(vout_o) <+ transition(vout);
    end

endmodule

`include "constants.vams"
`include "disciplines.vams"

// noise_gen — EVAS-compatible version.
// Adds Gaussian noise to vin_i using @(timer) sampling so that
// the output remains explicitly sample-and-hold, which is both low-warning and
// a good fit for this benchmark's intended behavior.

module noise_gen (
    input electrical  vin_i,
    output electrical vout_o
);

    parameter real sigma = 0.01;   // Noise std-dev (V)
    parameter real dt    = 0.5n;   // Sampling interval (s)

    real noise, vout;

    analog begin
        @(initial_step) begin
            noise = 0.0;
            vout  = 0.0;
            $strobe("[noise_gen] INIT | sigma=%.5gV dt=%.3gns", sigma, dt*1e9);
        end

        // Resample noise at each timer tick — makes vout piecewise-constant
        @(timer(dt)) begin
            noise = sigma * $rdist_normal(0, 0, 1);
            vout  = V(vin_i) + noise;
            $strobe("[noise_gen] t=%.3f ns | noise=%.5gV vout=%.5gV", $abstime*1e9, noise, vout);
        end

        V(vout_o) <+ transition(vout, 0, dt/10, dt/10);
    end

endmodule

// noise_gen gold smoke testbench
// DC input at 1.0V; noise_gen adds Gaussian noise (sigma=0.1V, dt=0.5ns).
// Runs 500ns. Check: std(noise) > 0.01V, max|noise| > 0.05V.
simulator lang=spectre
global 0

ahdl_include "noise_gen_ref.va"

Vvin (vin_i 0) vsource type=dc dc=1.0

IDUT (vin_i vout_o) noise_gen sigma=0.1 dt=0.5n

tran tran stop=500n maxstep=1n
save vin_i vout_o

