integer state_4_i;
integer state_5_i;
integer state_6_i;
integer feedback;
integer serial_bit;

analog begin
    @(initial_step) begin
        state_0_i = (seed >> 0) & 1;
        state_1_i = (seed >> 1) & 1;
        state_2_i = (seed >> 2) & 1;
        state_3_i = (seed >> 3) & 1;
        state_4_i = (seed >> 4) & 1;
        state_5_i = (seed >> 5) & 1;
        state_6_i = (seed >> 6) & 1;
        if (state_0_i == 0 && state_1_i == 0 && state_2_i == 0 && state_3_i == 0 &&
            state_4_i == 0 && state_5_i == 0 && state_6_i == 0)
            state_6_i = 1;
    end

    @(cross(V(clk) - vth, +1)) begin
        if (V(rst_n) < vth) begin
            state_0_i = (seed >> 0) & 1;
            state_1_i = (seed >> 1) & 1;
            state_2_i = (seed >> 2) & 1;
            state_3_i = (seed >> 3) & 1;
            state_4_i = (seed >> 4) & 1;
            state_5_i = (seed >> 5) & 1;
            state_6_i = (seed >> 6) & 1;
            if (state_0_i == 0 && state_1_i == 0 && state_2_i == 0 && state_3_i == 0 &&
                state_4_i == 0 && state_5_i == 0 && state_6_i == 0)
                state_6_i = 1;
        end else if (V(en) > vth) begin
            feedback = state_6_i ^ state_5_i;
            state_6_i = state_5_i;
            state_5_i = state_4_i;
            state_4_i = state_3_i;
            state_3_i = state_2_i;
            state_2_i = state_1_i;
            state_1_i = state_0_i;
            state_0_i = feedback;
        end
    end

    serial_bit = state_6_i;

    V(serial_out) <+ transition(serial_bit ? vdd : 0.0, td, trf, trf);
    V(state_0)    <+ transition(state_0_i ? vdd : 0.0, td, trf, trf);
    V(state_1)    <+ transition(state_1_i ? vdd : 0.0, td, trf, trf);
    V(state_2)    <+ transition(state_2_i ? vdd : 0.0, td, trf, trf);
    V(state_3)    <+ transition(state_3_i ? vdd : 0.0, td, trf, trf);
    V(state_4)    <+ transition(state_4_i ? vdd : 0.0, td, trf, trf);
    V(state_5)    <+ transition(state_5_i ? vdd : 0.0, td, trf, trf);
    V(state_6)    <+ transition(state_6_i ? vdd : 0.0, td, trf, trf);
end

endmodule

// 31-bit LFSR behavioral gold
// Maximal-length polynomial: taps at 31, 21, 1, 0.
// DPN output stored as piecewise-constant real (updated in event blocks).

`include "constants.vams"
`include "disciplines.vams"

`define N_lfsr 31
`default_transition 10p

module lfsr(
    output electrical DPN,
    inout  electrical VDD,
    inout  electrical VSS,
    input  electrical CLK,
    input  electrical EN,
    input  electrical RSTB
);

parameter integer seed = 123;

real    vtrans_clk;
integer lfsr_r[`N_lfsr:0];
integer tmp_lfsr_r[(`N_lfsr+1):0];
integer i;
real    dpn_level;   // piecewise-constant output voltage

analog begin
    @(initial_step or cross(V(RSTB) - 0.5, -1)) begin
        vtrans_clk = 0.5;
        for (i = 0; i <= `N_lfsr; i = i + 1) begin
            lfsr_r[i] = (seed >> i) & 1;
        end
        // Ensure seed is non-zero
        for (i = 0; i <= `N_lfsr; i = i + 5) begin
            lfsr_r[i] = 1;
        end
        dpn_level = lfsr_r[`N_lfsr] > 0 ? V(VDD) : V(VSS);
        $strobe("[lfsr] t=%.3f ns | INIT/RST | seed=%d | DPN=%d",
                $abstime*1e9, seed, lfsr_r[`N_lfsr]);
    end

    @(cross(V(CLK) - 0.5, +1)) begin
        if (V(RSTB) > 0.5) begin
            for (i = 0; i <= `N_lfsr; i = i + 1) begin
                tmp_lfsr_r[i + 1] = lfsr_r[i];
            end
            tmp_lfsr_r[0] = lfsr_r[31] ^ lfsr_r[21] ^ lfsr_r[1] ^ lfsr_r[0];
            for (i = 0; i <= `N_lfsr; i = i + 1) begin
                lfsr_r[i] = tmp_lfsr_r[i];
            end
            dpn_level = lfsr_r[`N_lfsr] > 0 ? V(VDD) : V(VSS);
            $strobe("[lfsr] t=%.3f ns | DPN=%d", $abstime*1e9, lfsr_r[`N_lfsr]);
        end
    end

    V(DPN) <+ transition(dpn_level, 0, 50p, 50p);
end

endmodule

