        @(cross(V(rst_n)-vth,-1)) begin streak=0; locked=0; last_fb=-1.0; end
        @(cross(V(fb_clk)-vth,+1)) last_fb = $abstime;
        @(cross(V(ref_clk)-vth,+1)) begin
            if (V(rst_n)<vth) begin streak=0; locked=0; end
            else begin
                if (last_fb>=0.0 && abs($abstime-last_fb) <= tol) streak=streak+1; else streak=0;
                if (streak>=need) locked=1;
            end
        end
        V(lock) <+ transition(locked ? vdd : 0.0, 0, tr, tr);
    end
endmodule

