`include "disciplines.vams"
`include "constants.vams"

// Set default transition time to 10ps
`default_transition 10p

(* ignore_hidden_state *)

module edge_interval_timer(CLK_1, CLK_2, OUT_PS);
    input CLK_1, CLK_2;
    output OUT_PS;
    electrical CLK_1, CLK_2, OUT_PS;

    // Threshold voltage parameter 0.4V
    parameter real VTH = 0.4;

    // Internal variables
    real t_start;
    real t_diff_ps; // Time difference stored in picoseconds
    real t_diff_ps_prev; // Previous delay for difference calculation
    integer is_armed;

    analog begin
        // Initialize values
        @ (initial_step) begin
            t_start = 0.0;
            t_diff_ps = 0.0;
            t_diff_ps_prev = 0.0;
            is_armed = 0;
        end

        // Capture CLK_1 rising edge
        @(cross(V(CLK_1) - VTH, +1)) begin
            t_start = $abstime;
            is_armed = 1;
        end

        // Capture CLK_2 rising edge and calculate delta
        @(cross(V(CLK_2) - VTH, +1)) begin
            if (is_armed == 1) begin
                // Convert (seconds) to (picoseconds): 1s = 1e12 ps
                t_diff_ps = ($abstime - t_start) * 1e12;
                is_armed = 0;

                // Print current delay and difference with last delay
                $strobe("[edge_interval_timer] t=%.3f ns | delay=%.3f ps | diff=%.3f ps", $abstime*1e9, t_diff_ps, t_diff_ps - t_diff_ps_prev);

                // Update previous delay for next measurement
                t_diff_ps_prev = t_diff_ps;
            end
        end

        // Drive the output port with the calculated value
        // The value remains held until the next measurement is completed
        V(OUT_PS) <+ transition(t_diff_ps, 0, 10p);

    end
endmodule

// cmp_delay: log-linear regeneration delay  td = td_0 + tau*ln(VDD/|Vdiff|)
// tau=4.34ps, td_0=20.5ps  →  10mV:40ps, 1mV:50ps, 0.1mV:60ps, 0.01mV:70ps
// Four 4ns phases (4 clk cycles each) spanning 3 decades of |diff|, 1GHz 50% duty
// VCM=0.45V (VDD/2), all positive polarity (vinp > vinn)
simulator lang=spectre
global 0

ahdl_include "cmp_delay.va"
ahdl_include "edge_interval_timer.va"

// Power supplies
Vvdd (vdd 0) vsource dc=0.9 type=dc
Vgnd (gnd 0) vsource dc=0.0 type=dc

// Clock: 1GHz, 50% duty cycle, delay=100ps
Vclk (clk 0) vsource type=pulse val0=0 val1=0.9 period=1n delay=100p \
        rise=50p fall=50p width=450p

// Differential input: VCM=0.45V, 4 phases × 4ns (4 clk cycles each)
// Phase 1  (0-4ns):  diff=+10mV   (VINP=455mV,     VINN=445mV)
// Phase 2  (4-8ns):  diff=+1mV    (VINP=450.5mV,   VINN=449.5mV)
// Phase 3  (8-12ns): diff=+0.1mV  (VINP=450.05mV,  VINN=449.95mV)
// Phase 4 (12-16ns): diff=+0.01mV (VINP=450.005mV, VINN=449.995mV)
Vvinp (vinp 0) vsource type=pwl wave=[0 0.455 3.9e-9 0.455 4e-9 0.4505 7.9e-9 0.4505 8e-9 0.45005 11.9e-9 0.45005 12e-9 0.450005 16e-9 0.450005]
Vvinn (vinn 0) vsource type=pwl wave=[0 0.445 3.9e-9 0.445 4e-9 0.4495 7.9e-9 0.4495 8e-9 0.44995 11.9e-9 0.44995 12e-9 0.449995 16e-9 0.449995]

// DUT (port order: CLK VINN VINP DCMPN DCMPP LP LM VSS VDD)
IDUT (clk vinn vinp out_n out_p lp_int lm_int gnd vdd) cmp_delay

// Edge-interval timer: measures CLK→out_p propagation delay
IEIT (clk out_p delay_ps) edge_interval_timer VTH=0.45

tran tran stop=16n maxstep=10p
save clk vinp vinn out_p out_n delay_ps

