               + (V(seg12) > vth ? 1 : 0)
               + (V(seg13) > vth ? 1 : 0)
               + (V(seg14) > vth ? 1 : 0);
        y = V(vss) + (V(vref) - V(vss)) * active / 15.0;
        V(aout, vss) <+ transition(y - V(vss), 0, tr, tr);
    end
endmodule

