module iq_downconversion_chain(clk, rst, vin, out, metric, lo_i, lo_q, mix_i, mix_q, phase_mon);
input clk, rst, vin;
output out, metric, lo_i, lo_q, mix_i, mix_q, phase_mon;
electrical clk, rst, vin, out, metric, lo_i, lo_q, mix_i, mix_q, phase_mon;
parameter real tr = 80p;
parameter real vth = 0.45;
real basev, iv, qv, icoef, qcoef, lo_i_v, lo_q_v, mix_i_v, mix_q_v, phase_v;
integer phase;
analog begin
    @(initial_step) begin
        phase = 3;
        iv = 0.45;
        qv = 0.45;
        lo_i_v = 0.45;
        lo_q_v = 0.45;
        mix_i_v = 0.45;
        mix_q_v = 0.45;
        phase_v = 0.9;
    end
    @(cross(V(clk) - vth, +1)) begin
        if (V(rst) > vth) begin
            phase = 3;
            iv = 0.45;
            qv = 0.45;
            lo_i_v = 0.45;
            lo_q_v = 0.45;
            mix_i_v = 0.45;
            mix_q_v = 0.45;
            phase_v = 0.9;
        end else begin
            phase = phase + 1;
            if (phase > 3) phase = 0;
            if (phase == 0) icoef = 1.0;
            else if (phase == 1) icoef = 0.0;
            else if (phase == 2) icoef = -1.0;
            else icoef = 0.0;
            if (phase == 0) qcoef = 0.0;
            else if (phase == 1) qcoef = 1.0;
            else if (phase == 2) qcoef = 0.0;
