`define NUM_BITS 8
`default_transition 30p

// 8-bit combinatorial binary-weighted DAC.
//
// Weights (MSB→LSB): 128, 64, 32, 16, 8, 4, 2, 1  (total_sum = 255).
// DIN7 = MSB (weight 128),  DIN0 = LSB (weight 1).
//
// VOUT = (sum of active weights) / 255 * vdd.
//
// Evaluates every time step (combinatorial — no clock needed).
// Pin mapping is identical to sar_adc_weighted_8b DOUT for zero-error
// round-trip reconstruction.

module dac_weighted_8b(
    input  electrical                 DIN7,
    input  electrical                 DIN6,
    input  electrical                 DIN5,
    input  electrical                 DIN4,
    input  electrical                 DIN3,
    input  electrical                 DIN2,
    input  electrical                 DIN1,
    input  electrical                 DIN0,
    output electrical                 VOUT
);

parameter real vdd = 0.9;
parameter real vth = 0.45;

real vout_val;
real code_val;

analog begin
    @(initial_step) begin
        vout_val = 0;
        code_val = 0;
        $strobe("[dac_weighted_8b] INIT | vdd=%.3gV | total_sum=255", vdd);
    end

    // Explicit event-triggered accumulation avoids simulator-specific analog
    // loop/index handling and recomputes the DAC output whenever a code bit
    // crosses its voltage-coded logic threshold.
    @(initial_step
      or cross(V(DIN7) - vth, +1) or cross(V(DIN7) - vth, -1)
      or cross(V(DIN6) - vth, +1) or cross(V(DIN6) - vth, -1)
      or cross(V(DIN5) - vth, +1) or cross(V(DIN5) - vth, -1)
      or cross(V(DIN4) - vth, +1) or cross(V(DIN4) - vth, -1)
      or cross(V(DIN3) - vth, +1) or cross(V(DIN3) - vth, -1)
      or cross(V(DIN2) - vth, +1) or cross(V(DIN2) - vth, -1)
      or cross(V(DIN1) - vth, +1) or cross(V(DIN1) - vth, -1)
      or cross(V(DIN0) - vth, +1) or cross(V(DIN0) - vth, -1)) begin
        code_val = 0.0;
        if (V(DIN7) > vth) code_val = code_val + 128.0;
        if (V(DIN6) > vth) code_val = code_val + 64.0;
        if (V(DIN5) > vth) code_val = code_val + 32.0;
        if (V(DIN4) > vth) code_val = code_val + 16.0;
        if (V(DIN3) > vth) code_val = code_val + 8.0;
        if (V(DIN2) > vth) code_val = code_val + 4.0;
        if (V(DIN1) > vth) code_val = code_val + 2.0;
        if (V(DIN0) > vth) code_val = code_val + 1.0;
        vout_val = code_val / 255.0 * vdd;
    end

    V(VOUT) <+ transition(vout_val, 0);
end

endmodule

`include "constants.vams"
`include "disciplines.vams"

`define NUM_BITS 8
`default_transition 30p

// 8-bit SAR ADC with configurable binary weights.
//
// Default weights (MSB→LSB): 128, 64, 32, 16, 8, 4, 2, 1
// total_sum = 255.  Input [0, vdd] → code [0, 255].
//
// Algorithm: start one conversion on a falling CLKS edge, then resolve one SAR
// trial bit on each following rising CLKS edge.  The public monitor outputs show
// the currently active bit, trial code, trial DAC voltage, comparator decision,
// sampled input, and conversion-done state.
//
// Sampling phase: explicitly sample VIN on CLKS falling edge when idle.
// Conversion: one MSB-to-LSB trial per rising CLKS edge.
// RST_N: active-low synchronous reset — clears all output bits.
//
// Output mapping: DOUT[7] = MSB (weight 128), DOUT[0] = LSB (weight 1).
// Matches dac_weighted_8b pin-for-pin for a zero-error round-trip.

module sar_adc_weighted_8b(
    input  electrical               VIN,
    input  electrical               CLKS,
    input  electrical               RST_N,
    output electrical [`NUM_BITS-1:0] DOUT,
    output electrical               BIT_INDEX,
    output electrical               TRIAL_CODE_MON,
    output electrical               TRIAL_VDAC,
    output electrical               CMP_DECISION,
    output electrical               CONV_DONE,
    output electrical               VIN_SAMPLE
);

parameter real vdd = 0.9;
parameter real vth = 0.45;

real weight[`NUM_BITS:1];   // weight[8]=MSB, weight[1]=LSB
real total_sum;
real vsampled, vdac_partial, trial_vdac_state;
real bit_index_v, trial_code_v, cmp_decision_v, conv_done_v;
integer dout_bits[`NUM_BITS:1];
integer trial_bits[`NUM_BITS:1];
integer bit_idx;
integer busy;
integer final_code;
integer trial_code_int;

analog begin
    @(initial_step) begin
        weight[8] = 128; weight[7] = 64; weight[6] = 32; weight[5] = 16;
        weight[4] = 8;   weight[3] = 4;  weight[2] = 2;  weight[1] = 1;

        total_sum = 255;

        dout_bits[8] = 0; dout_bits[7] = 0; dout_bits[6] = 0; dout_bits[5] = 0;
        dout_bits[4] = 0; dout_bits[3] = 0; dout_bits[2] = 0; dout_bits[1] = 0;
        trial_bits[8] = 0; trial_bits[7] = 0; trial_bits[6] = 0; trial_bits[5] = 0;
        trial_bits[4] = 0; trial_bits[3] = 0; trial_bits[2] = 0; trial_bits[1] = 0;
        vdac_partial = 0.0;
        trial_vdac_state = 0.0;
        vsampled = 0.0;
        bit_idx = 0;
        busy = 0;
        final_code = 0;
        trial_code_int = 0;
        bit_index_v = 0.0;
        trial_code_v = 0.0;
        cmp_decision_v = 0.0;
        conv_done_v = 0.0;

        $strobe("[sar_adc_weighted_8b] INIT | vdd=%.3gV | total_sum=%g", vdd, total_sum);
    end

    // Start a conversion by sampling the held input when the ADC is idle.
    @(cross(V(CLKS) - vth, -1)) begin
        if (V(RST_N) >= vth && busy == 0) begin
            vsampled = V(VIN);
            vdac_partial = 0.0;
            bit_idx = 8;
            busy = 1;
            conv_done_v = 0.0;
            final_code = 0;

            dout_bits[8] = 0; dout_bits[7] = 0; dout_bits[6] = 0; dout_bits[5] = 0;
            dout_bits[4] = 0; dout_bits[3] = 0; dout_bits[2] = 0; dout_bits[1] = 0;
            trial_bits[8] = 1; trial_bits[7] = 0; trial_bits[6] = 0; trial_bits[5] = 0;
            trial_bits[4] = 0; trial_bits[3] = 0; trial_bits[2] = 0; trial_bits[1] = 0;
            trial_code_int = 128;
            trial_vdac_state = trial_code_int / total_sum * vdd;
            cmp_decision_v = (vsampled >= trial_vdac_state) ? vdd : 0.0;
            bit_index_v = bit_idx / 8.0 * vdd;
            trial_code_v = trial_code_int / total_sum * vdd;
        end
    end

    // Resolve exactly one SAR trial bit on each rising clock edge.
    @(cross(V(CLKS) - vth, +1)) begin
        if (V(RST_N) < vth) begin
            dout_bits[8] = 0; dout_bits[7] = 0; dout_bits[6] = 0; dout_bits[5] = 0;
            dout_bits[4] = 0; dout_bits[3] = 0; dout_bits[2] = 0; dout_bits[1] = 0;
            trial_bits[8] = 0; trial_bits[7] = 0; trial_bits[6] = 0; trial_bits[5] = 0;
            trial_bits[4] = 0; trial_bits[3] = 0; trial_bits[2] = 0; trial_bits[1] = 0;
            vdac_partial = 0.0;
            trial_vdac_state = 0.0;
            bit_idx = 0;
            busy = 0;
            final_code = 0;
            trial_code_int = 0;
            bit_index_v = 0.0;
            trial_code_v = 0.0;
            cmp_decision_v = 0.0;
            conv_done_v = 0.0;
        end else begin
            if (busy == 1 && bit_idx > 0) begin
                if (cmp_decision_v > vth) begin
                    if (bit_idx == 8) dout_bits[8] = 1;
                    else if (bit_idx == 7) dout_bits[7] = 1;
                    else if (bit_idx == 6) dout_bits[6] = 1;
                    else if (bit_idx == 5) dout_bits[5] = 1;
                    else if (bit_idx == 4) dout_bits[4] = 1;
                    else if (bit_idx == 3) dout_bits[3] = 1;
                    else if (bit_idx == 2) dout_bits[2] = 1;
                    else if (bit_idx == 1) dout_bits[1] = 1;
                    if (bit_idx == 8) vdac_partial = vdac_partial + 128;
                    else if (bit_idx == 7) vdac_partial = vdac_partial + 64;
                    else if (bit_idx == 6) vdac_partial = vdac_partial + 32;
                    else if (bit_idx == 5) vdac_partial = vdac_partial + 16;
                    else if (bit_idx == 4) vdac_partial = vdac_partial + 8;
                    else if (bit_idx == 3) vdac_partial = vdac_partial + 4;
                    else if (bit_idx == 2) vdac_partial = vdac_partial + 2;
                    else if (bit_idx == 1) vdac_partial = vdac_partial + 1;
                end

                bit_idx = bit_idx - 1;
                if (bit_idx > 0) begin
                    trial_bits[8] = dout_bits[8]; trial_bits[7] = dout_bits[7];
                    trial_bits[6] = dout_bits[6]; trial_bits[5] = dout_bits[5];
                    trial_bits[4] = dout_bits[4]; trial_bits[3] = dout_bits[3];
                    trial_bits[2] = dout_bits[2]; trial_bits[1] = dout_bits[1];
                    if (bit_idx == 8) trial_bits[8] = 1;
                    else if (bit_idx == 7) trial_bits[7] = 1;
                    else if (bit_idx == 6) trial_bits[6] = 1;
                    else if (bit_idx == 5) trial_bits[5] = 1;
                    else if (bit_idx == 4) trial_bits[4] = 1;
                    else if (bit_idx == 3) trial_bits[3] = 1;
                    else if (bit_idx == 2) trial_bits[2] = 1;
                    else if (bit_idx == 1) trial_bits[1] = 1;

                    trial_code_int = trial_bits[8] * 128 + trial_bits[7] * 64
                                   + trial_bits[6] * 32 + trial_bits[5] * 16
                                   + trial_bits[4] * 8 + trial_bits[3] * 4
                                   + trial_bits[2] * 2 + trial_bits[1];
                    trial_vdac_state = trial_code_int / total_sum * vdd;
                    cmp_decision_v = (vsampled >= trial_vdac_state) ? vdd : 0.0;
                    bit_index_v = bit_idx / 8.0 * vdd;
                    trial_code_v = trial_code_int / total_sum * vdd;
                    conv_done_v = 0.0;
                end else begin
                    final_code = dout_bits[8] * 128 + dout_bits[7] * 64
                               + dout_bits[6] * 32 + dout_bits[5] * 16
                               + dout_bits[4] * 8 + dout_bits[3] * 4
                               + dout_bits[2] * 2 + dout_bits[1];
                    trial_code_int = final_code;
                    trial_vdac_state = final_code / total_sum * vdd;
                    trial_code_v = trial_vdac_state;
                    bit_index_v = 0.0;
                    cmp_decision_v = (vsampled >= trial_vdac_state) ? vdd : 0.0;
                    conv_done_v = vdd;
                    busy = 0;
                    $strobe("[sar_adc_weighted_8b] t=%.3f ns | vin=%.5gV | final_code=%d",
                            $abstime*1e9, vsampled, final_code);
                end
            end
        end
    end

    // DOUT[7]=MSB (weight[8]=128), DOUT[0]=LSB (weight[1]=1)
    V(DOUT[7]) <+ transition(dout_bits[8] ? vdd : 0, 0);
    V(DOUT[6]) <+ transition(dout_bits[7] ? vdd : 0, 0);
    V(DOUT[5]) <+ transition(dout_bits[6] ? vdd : 0, 0);
    V(DOUT[4]) <+ transition(dout_bits[5] ? vdd : 0, 0);
    V(DOUT[3]) <+ transition(dout_bits[4] ? vdd : 0, 0);
    V(DOUT[2]) <+ transition(dout_bits[3] ? vdd : 0, 0);
    V(DOUT[1]) <+ transition(dout_bits[2] ? vdd : 0, 0);
    V(DOUT[0]) <+ transition(dout_bits[1] ? vdd : 0, 0);
    V(BIT_INDEX) <+ transition(bit_index_v, 0);
    V(TRIAL_CODE_MON) <+ transition(trial_code_v, 0);
    V(TRIAL_VDAC) <+ transition(trial_vdac_state, 0);
    V(CMP_DECISION) <+ transition(cmp_decision_v, 0);
    V(CONV_DONE) <+ transition(conv_done_v, 0);
    V(VIN_SAMPLE) <+ transition(vsampled, 0);
end

endmodule

// sh_ideal.va -- ideal sample-and-hold
//
// Samples vin on the rising edge of clk (same edge as adc_ideal_4b).
// Holds the sampled value until the next rising edge.
// Output uses transition() with tr=30p to match adc_ideal_4b/dac_ideal_4b.
// Reset (active-low rst_n) holds output at 0 V until deasserted.

`include "disciplines.vams"
`default_transition 30p

module sh_ideal(vin, clk, vdd, vss, rst_n, vout);
    input  vin, clk, vdd, vss, rst_n;
    output vout;
    electrical vin, clk, vdd, vss, rst_n, vout;

    parameter real tr = 30p from [0:inf);

    real v_hold, vth;

    analog begin
        @(initial_step) begin
            v_hold = 0.0;
            $strobe("[sh_ideal] INIT | vdd_vss=%.3gV", V(vdd, vss));
        end

        vth = (V(vdd) + V(vss)) / 2.0;

        @(cross(V(clk, vss) - vth, +1)) begin
            if (V(rst_n, vss) > vth)
                v_hold = V(vin, vss);
        end

        V(vout, vss) <+ transition(v_hold, 0, tr);
    end
endmodule

`include "constants.vams"
`include "disciplines.vams"

`define NUM_BITS 8
`default_transition 30p

// 8-bit combinatorial binary-weighted DAC.
//
// Weights (MSB→LSB): 128, 64, 32, 16, 8, 4, 2, 1  (total_sum = 255).
// DIN7 = MSB (weight 128),  DIN0 = LSB (weight 1).
//
// VOUT = (sum of active weights) / 255 * vdd.
//
// Evaluates every time step (combinatorial — no clock needed).
// Pin mapping is identical to sar_adc_weighted_8b DOUT for zero-error
// round-trip reconstruction.

module dac_weighted_8b(
    input  electrical                 DIN7,
    input  electrical                 DIN6,
    input  electrical                 DIN5,
    input  electrical                 DIN4,
    input  electrical                 DIN3,
    input  electrical                 DIN2,
    input  electrical                 DIN1,
    input  electrical                 DIN0,
    output electrical                 VOUT
);

parameter real vdd = 0.9;
parameter real vth = 0.45;

real vout_val;
real code_val;

analog begin
    @(initial_step) begin
        vout_val = 0;
        code_val = 0;
        $strobe("[dac_weighted_8b] INIT | vdd=%.3gV | total_sum=255", vdd);
    end

    // Explicit event-triggered accumulation avoids simulator-specific analog
    // loop/index handling and recomputes the DAC output whenever a code bit
    // crosses its voltage-coded logic threshold.
    @(initial_step
      or cross(V(DIN7) - vth, +1) or cross(V(DIN7) - vth, -1)
      or cross(V(DIN6) - vth, +1) or cross(V(DIN6) - vth, -1)
      or cross(V(DIN5) - vth, +1) or cross(V(DIN5) - vth, -1)
      or cross(V(DIN4) - vth, +1) or cross(V(DIN4) - vth, -1)
      or cross(V(DIN3) - vth, +1) or cross(V(DIN3) - vth, -1)
      or cross(V(DIN2) - vth, +1) or cross(V(DIN2) - vth, -1)
      or cross(V(DIN1) - vth, +1) or cross(V(DIN1) - vth, -1)
      or cross(V(DIN0) - vth, +1) or cross(V(DIN0) - vth, -1)) begin
        code_val = 0.0;
        if (V(DIN7) > vth) code_val = code_val + 128.0;
        if (V(DIN6) > vth) code_val = code_val + 64.0;
        if (V(DIN5) > vth) code_val = code_val + 32.0;
        if (V(DIN4) > vth) code_val = code_val + 16.0;
        if (V(DIN3) > vth) code_val = code_val + 8.0;
        if (V(DIN2) > vth) code_val = code_val + 4.0;
        if (V(DIN1) > vth) code_val = code_val + 2.0;
        if (V(DIN0) > vth) code_val = code_val + 1.0;
        vout_val = code_val / 255.0 * vdd;
    end

    V(VOUT) <+ transition(vout_val, 0);
end

endmodule

`include "constants.vams"
`include "disciplines.vams"

`define NUM_BITS 8
`default_transition 30p

// 8-bit SAR ADC with configurable binary weights.
//
// Default weights (MSB→LSB): 128, 64, 32, 16, 8, 4, 2, 1
// total_sum = 255.  Input [0, vdd] → code [0, 255].
//
// Algorithm: start one conversion on a falling CLKS edge, then resolve one SAR
// trial bit on each following rising CLKS edge.  The public monitor outputs show
// the currently active bit, trial code, trial DAC voltage, comparator decision,
// sampled input, and conversion-done state.
//
// Sampling phase: explicitly sample VIN on CLKS falling edge when idle.
// Conversion: one MSB-to-LSB trial per rising CLKS edge.
// RST_N: active-low synchronous reset — clears all output bits.
//
// Output mapping: DOUT[7] = MSB (weight 128), DOUT[0] = LSB (weight 1).
// Matches dac_weighted_8b pin-for-pin for a zero-error round-trip.

module sar_adc_weighted_8b(
    input  electrical               VIN,
    input  electrical               CLKS,
    input  electrical               RST_N,
    output electrical [`NUM_BITS-1:0] DOUT,
    output electrical               BIT_INDEX,
    output electrical               TRIAL_CODE_MON,
    output electrical               TRIAL_VDAC,
    output electrical               CMP_DECISION,
    output electrical               CONV_DONE,
    output electrical               VIN_SAMPLE
);

parameter real vdd = 0.9;
parameter real vth = 0.45;

real weight[`NUM_BITS:1];   // weight[8]=MSB, weight[1]=LSB
real total_sum;
real vsampled, vdac_partial, trial_vdac_state;
real bit_index_v, trial_code_v, cmp_decision_v, conv_done_v;
integer dout_bits[`NUM_BITS:1];
integer trial_bits[`NUM_BITS:1];
integer bit_idx;
integer busy;
integer final_code;
integer trial_code_int;

analog begin
    @(initial_step) begin
        weight[8] = 128; weight[7] = 64; weight[6] = 32; weight[5] = 16;
        weight[4] = 8;   weight[3] = 4;  weight[2] = 2;  weight[1] = 1;

        total_sum = 255;

        dout_bits[8] = 0; dout_bits[7] = 0; dout_bits[6] = 0; dout_bits[5] = 0;
        dout_bits[4] = 0; dout_bits[3] = 0; dout_bits[2] = 0; dout_bits[1] = 0;
        trial_bits[8] = 0; trial_bits[7] = 0; trial_bits[6] = 0; trial_bits[5] = 0;
        trial_bits[4] = 0; trial_bits[3] = 0; trial_bits[2] = 0; trial_bits[1] = 0;
        vdac_partial = 0.0;
        trial_vdac_state = 0.0;
        vsampled = 0.0;
        bit_idx = 0;
        busy = 0;
        final_code = 0;
        trial_code_int = 0;
        bit_index_v = 0.0;
        trial_code_v = 0.0;
        cmp_decision_v = 0.0;
        conv_done_v = 0.0;

        $strobe("[sar_adc_weighted_8b] INIT | vdd=%.3gV | total_sum=%g", vdd, total_sum);
    end

    // Start a conversion by sampling the held input when the ADC is idle.
    @(cross(V(CLKS) - vth, -1)) begin
        if (V(RST_N) >= vth && busy == 0) begin
            vsampled = V(VIN);
            vdac_partial = 0.0;
            bit_idx = 8;
            busy = 1;
            conv_done_v = 0.0;
            final_code = 0;

            dout_bits[8] = 0; dout_bits[7] = 0; dout_bits[6] = 0; dout_bits[5] = 0;
            dout_bits[4] = 0; dout_bits[3] = 0; dout_bits[2] = 0; dout_bits[1] = 0;
            trial_bits[8] = 1; trial_bits[7] = 0; trial_bits[6] = 0; trial_bits[5] = 0;
            trial_bits[4] = 0; trial_bits[3] = 0; trial_bits[2] = 0; trial_bits[1] = 0;
            trial_code_int = 128;
            trial_vdac_state = trial_code_int / total_sum * vdd;
            cmp_decision_v = (vsampled >= trial_vdac_state) ? vdd : 0.0;
            bit_index_v = bit_idx / 8.0 * vdd;
            trial_code_v = trial_code_int / total_sum * vdd;
        end
    end

    // Resolve exactly one SAR trial bit on each rising clock edge.
    @(cross(V(CLKS) - vth, +1)) begin
        if (V(RST_N) < vth) begin
            dout_bits[8] = 0; dout_bits[7] = 0; dout_bits[6] = 0; dout_bits[5] = 0;
            dout_bits[4] = 0; dout_bits[3] = 0; dout_bits[2] = 0; dout_bits[1] = 0;
            trial_bits[8] = 0; trial_bits[7] = 0; trial_bits[6] = 0; trial_bits[5] = 0;
            trial_bits[4] = 0; trial_bits[3] = 0; trial_bits[2] = 0; trial_bits[1] = 0;
            vdac_partial = 0.0;
            trial_vdac_state = 0.0;
            bit_idx = 0;
            busy = 0;
            final_code = 0;
            trial_code_int = 0;
            bit_index_v = 0.0;
            trial_code_v = 0.0;
            cmp_decision_v = 0.0;
            conv_done_v = 0.0;
        end else begin
            if (busy == 1 && bit_idx > 0) begin
                if (cmp_decision_v > vth) begin
                    if (bit_idx == 8) dout_bits[8] = 1;
                    else if (bit_idx == 7) dout_bits[7] = 1;
                    else if (bit_idx == 6) dout_bits[6] = 1;
                    else if (bit_idx == 5) dout_bits[5] = 1;
                    else if (bit_idx == 4) dout_bits[4] = 1;
                    else if (bit_idx == 3) dout_bits[3] = 1;
                    else if (bit_idx == 2) dout_bits[2] = 1;
                    else if (bit_idx == 1) dout_bits[1] = 1;
                    if (bit_idx == 8) vdac_partial = vdac_partial + 128;
                    else if (bit_idx == 7) vdac_partial = vdac_partial + 64;
                    else if (bit_idx == 6) vdac_partial = vdac_partial + 32;
                    else if (bit_idx == 5) vdac_partial = vdac_partial + 16;
                    else if (bit_idx == 4) vdac_partial = vdac_partial + 8;
                    else if (bit_idx == 3) vdac_partial = vdac_partial + 4;
                    else if (bit_idx == 2) vdac_partial = vdac_partial + 2;
                    else if (bit_idx == 1) vdac_partial = vdac_partial + 1;
                end

                bit_idx = bit_idx - 1;
                if (bit_idx > 0) begin
                    trial_bits[8] = dout_bits[8]; trial_bits[7] = dout_bits[7];
                    trial_bits[6] = dout_bits[6]; trial_bits[5] = dout_bits[5];
                    trial_bits[4] = dout_bits[4]; trial_bits[3] = dout_bits[3];
                    trial_bits[2] = dout_bits[2]; trial_bits[1] = dout_bits[1];
                    if (bit_idx == 8) trial_bits[8] = 1;
                    else if (bit_idx == 7) trial_bits[7] = 1;
                    else if (bit_idx == 6) trial_bits[6] = 1;
                    else if (bit_idx == 5) trial_bits[5] = 1;
                    else if (bit_idx == 4) trial_bits[4] = 1;
                    else if (bit_idx == 3) trial_bits[3] = 1;
                    else if (bit_idx == 2) trial_bits[2] = 1;
                    else if (bit_idx == 1) trial_bits[1] = 1;

                    trial_code_int = trial_bits[8] * 128 + trial_bits[7] * 64
                                   + trial_bits[6] * 32 + trial_bits[5] * 16
                                   + trial_bits[4] * 8 + trial_bits[3] * 4
                                   + trial_bits[2] * 2 + trial_bits[1];
                    trial_vdac_state = trial_code_int / total_sum * vdd;
                    cmp_decision_v = (vsampled >= trial_vdac_state) ? vdd : 0.0;
                    bit_index_v = bit_idx / 8.0 * vdd;
                    trial_code_v = trial_code_int / total_sum * vdd;
                    conv_done_v = 0.0;
                end else begin
                    final_code = dout_bits[8] * 128 + dout_bits[7] * 64
                               + dout_bits[6] * 32 + dout_bits[5] * 16
                               + dout_bits[4] * 8 + dout_bits[3] * 4
                               + dout_bits[2] * 2 + dout_bits[1];
                    trial_code_int = final_code;
                    trial_vdac_state = final_code / total_sum * vdd;
                    trial_code_v = trial_vdac_state;
                    bit_index_v = 0.0;
                    cmp_decision_v = (vsampled >= trial_vdac_state) ? vdd : 0.0;
                    conv_done_v = vdd;
                    busy = 0;
                    $strobe("[sar_adc_weighted_8b] t=%.3f ns | vin=%.5gV | final_code=%d",
                            $abstime*1e9, vsampled, final_code);
                end
            end
        end
    end

    // DOUT[7]=MSB (weight[8]=128), DOUT[0]=LSB (weight[1]=1)
    V(DOUT[7]) <+ transition(dout_bits[8] ? vdd : 0, 0);
    V(DOUT[6]) <+ transition(dout_bits[7] ? vdd : 0, 0);
    V(DOUT[5]) <+ transition(dout_bits[6] ? vdd : 0, 0);
    V(DOUT[4]) <+ transition(dout_bits[5] ? vdd : 0, 0);
    V(DOUT[3]) <+ transition(dout_bits[4] ? vdd : 0, 0);
    V(DOUT[2]) <+ transition(dout_bits[3] ? vdd : 0, 0);
    V(DOUT[1]) <+ transition(dout_bits[2] ? vdd : 0, 0);
    V(DOUT[0]) <+ transition(dout_bits[1] ? vdd : 0, 0);
    V(BIT_INDEX) <+ transition(bit_index_v, 0);
    V(TRIAL_CODE_MON) <+ transition(trial_code_v, 0);
    V(TRIAL_VDAC) <+ transition(trial_vdac_state, 0);
    V(CMP_DECISION) <+ transition(cmp_decision_v, 0);
    V(CONV_DONE) <+ transition(conv_done_v, 0);
    V(VIN_SAMPLE) <+ transition(vsampled, 0);
end

endmodule

// sh_ideal.va -- ideal sample-and-hold
//
// Samples vin on the rising edge of clk (same edge as adc_ideal_4b).
// Holds the sampled value until the next rising edge.
// Output uses transition() with tr=30p to match adc_ideal_4b/dac_ideal_4b.
// Reset (active-low rst_n) holds output at 0 V until deasserted.

`include "disciplines.vams"
`default_transition 30p

module sh_ideal(vin, clk, vdd, vss, rst_n, vout);
    input  vin, clk, vdd, vss, rst_n;
    output vout;
    electrical vin, clk, vdd, vss, rst_n, vout;

    parameter real tr = 30p from [0:inf);

    real v_hold, vth;

    analog begin
        @(initial_step) begin
            v_hold = 0.0;
            $strobe("[sh_ideal] INIT | vdd_vss=%.3gV", V(vdd, vss));
        end

        vth = (V(vdd) + V(vss)) / 2.0;

        @(cross(V(clk, vss) - vth, +1)) begin
            if (V(rst_n, vss) > vth)
                v_hold = V(vin, vss);
        end

        V(vout, vss) <+ transition(v_hold, 0, tr);
    end
endmodule
